  });

  test("reads version from a plain VERSION file (trims whitespace)", () => {
    const dir = tmp();
    const path = join(dir, "VERSION");
    writeFileSync(path, "  v0.5.0  \n");
    expect(readVersionFile(path)).toBe("v0.5.0");
  });

