    const dir = tmp();
    const path = join(dir, "VERSION");
    writeFileSync(path, "v0.1.0\n");
    writeVersionFile(path, "0.2.0");
    expect(readFileSync(path, "utf8").trim()).toBe("0.2.0");
  });
});

