    const dir = tmp();
    const pkg = join(dir, "package.json");
    const log = join(dir, "commits.txt");
    writeFileSync(pkg, JSON.stringify({ name: "demo", version: "1.4.2" }, null, 2));
    writeFileSync(log, "feat!: drop legacy v1 api\n\nfix: random\n");

